module RefModule (
    input [7:0] data,
    input [7:0] checksum,
    output reg valid
);
    integer obf_i;
    reg [7:0] computed_checksum;

    always @* begin
        computed_checksum = 8'b0;
        for (obf_i = 0; obf_i < 8; obf_i = obf_i + 1) begin
            computed_checksum = computed_checksum + data[obf_i];
        end
        valid = (computed_checksum == checksum);
    end
endmodule
